import anthropic, fitz, base64, json
from concurrent.futures import ThreadPoolExecutor, as_completed

client = anthropic.Anthropic()

SYSTEM = (
    "You are a legal contract analyst. Extract only the requested clause types. "
    "Return JSON: {clauses: [{type, text, page}]}. "
    "If none found, return {clauses: []}."
)

def rasterise_chunk(pdf_path: str, start: int, end: int) -> list[dict]:
    doc = fitz.open(pdf_path)
    pages = []
    for i in range(start, min(end, len(doc))):
        pix = doc[i].get_pixmap(matrix=fitz.Matrix(1.5, 1.5), alpha=False)
        pages.append({
            "page": i + 1,
            "data": base64.standard_b64encode(pix.tobytes("png")).decode(),
        })
    doc.close()
    return pages

def extract_clauses(chunk: list[dict], clause_types: list[str]) -> dict:
    blocks = [
        {"type": "image", "source": {
            "type": "base64", "media_type": "image/png", "data": p["data"]
        }}
        for p in chunk
    ]
    page_range = f"{chunk[0]['page']}–{chunk[-1]['page']}"
    blocks.append({"type": "text", "text": (
        f"Pages {page_range}. Extract clauses of types: {clause_types}."
    )})
    resp = client.messages.create(
        model="claude-opus-4-5", max_tokens=1024, system=SYSTEM,
        messages=[{"role": "user", "content": blocks}],
    )
    return json.loads(resp.content[0].text)

def process_contract(pdf_path: str, clause_types: list[str], window: int = 5) -> list[dict]:
    doc = fitz.open(pdf_path)
    page_count = len(doc)
    doc.close()

    windows = [(i, i + window) for i in range(0, page_count, window)]
    all_clauses = []

    with ThreadPoolExecutor(max_workers=4) as pool:
        futures = {
            pool.submit(extract_clauses,
                        rasterise_chunk(pdf_path, s, e),
                        clause_types): (s, e)
            for s, e in windows
        }
        for fut in as_completed(futures):
            result = fut.result()
            all_clauses.extend(result.get("clauses", []))

    # Sort by page for coherent output
    all_clauses.sort(key=lambda c: c.get("page", 0))
    return all_clauses


if __name__ == "__main__":
    clauses = process_contract(
        "service_agreement.pdf",
        ["termination", "limitation_of_liability", "indemnification"],
    )
    for c in clauses:
        print(f"[Page {c['page']}] {c['type']}: {c['text'][:80]}...")

